// Loop over input items
for (const item of $input.all()) {

  const dateString = item.json.answer;

  // Initialize new fields
  item.json.isOver18 = false;
  item.json.validationError = null;

  // 1. Check if input exists
  if (!dateString) {
    item.json.validationError = "Input field 'answer' is missing or empty.";
    continue; // Skip to the next item
  }

  // 2. Check for exact dd/mm/yyyy format
  const regex = /^\d{2}\/\d{2}\/\d{4}$/;
  if (!regex.test(dateString)) {
    item.json.validationError = "Invalid date format. Expected dd/mm/yyyy.";
    continue; // Skip to the next item
  }

  // 3. Parse the date string
  const parts = dateString.split('/');
  const day = parseInt(parts[0], 10);
  const month = parseInt(parts[1], 10) - 1; // JavaScript months are 0-indexed (0-11)
  const year = parseInt(parts[2], 10);

  const birthDate = new Date(year, month, day);

  // 4. Validate if the created date is a real calendar date
  // This catches invalid dates like 31/02/2000, which JS would "roll over"
  if (birthDate.getFullYear() !== year || birthDate.getMonth() !== month || birthDate.getDate() !== day) {
    item.json.validationError = "Invalid calendar date (e.g., 31/02/2000).";
    continue; // Skip to the next item
  }

  // 5. Calculate the cutoff date (18 years ago from today)
  const today = new Date();
  const cutoffDate = new Date(
    today.getFullYear() - 18,
    today.getMonth(),
    today.getDate()
  );

  // 6. Perform the validation
  // If the birthdate is on or before the cutoff date, they are 18 or older.
  item.json.isOver18 = (birthDate <= cutoffDate);

}

return $input.all();

